263→function parseArgs(rawArgs: string[]): {
264→  options: Record<string, string | number | boolean>;
265→  target?: string;
266→  filters: Array<[string, string]>;
267→} {
268→  const options: Record<string, string | number | boolean> = {};
269→  const filters: Array<[string, string]> = [];
270→  let target: string | undefined;
271→
272→  for (let i = 0; i < rawArgs.length; i++) {
273→    const arg = rawArgs[i];
274→
275→    if (arg.startsWith("-")) {
276→      // Handle options
277→      const flagName = arg.replace(/^--?/, "");
278→
279→      // Map short flags to long names
280→      const flagMap: Record<string, string> = {
281→        e: "env",
282→        t: "trials",
283→        c: "concurrency",
284→        m: "model",
285→        p: "provider",
286→        l: "limit",
287→        s: "sample",
288→        f: "filter",
289→      };
290→
291→      const optionName = flagMap[flagName] || flagName;
292→
293→      if (optionName === "api") {
294→        options.api = true;
295→      } else if (optionName === "filter") {
296→        // Parse filter as key=value
297→        const filterValue = rawArgs[++i];
298→        if (filterValue && filterValue.includes("=")) {
299→          const [key, value] = filterValue.split("=");
300→          filters.push([key, value]);
301→        }
302→      } else {
303→        // Get next value
304→        const value = rawArgs[++i];
305→        if (value && !value.startsWith("-")) {
306→          // Parse numbers
307→          if (
308→            ["trials", "concurrency", "limit", "sample"].includes(optionName)
309→          ) {
310→            options[optionName] = parseInt(value, 10);
311→          } else {
312→            options[optionName] = value;
313→          }
314→        }
315→      }
316→    } else if (!target) {
317→      target = arg;
318→    }
319→  }
320→
321→  return { options, target, filters };
322→}
