  1→/**
  2→ * Keep this file in sync with:
  3→ * - /packages/core/lib/v3/runtimePaths.ts
  4→ * - /packages/server/scripts/runtimePaths.ts
  5→ * - /packages/evals/runtimePaths.ts
  6→ * - /packages/docs/scripts/runtimePaths.js
  7→ */
  8→import path from "node:path";
  9→import { fileURLToPath } from "node:url";
 10→import { createRequire } from "node:module";
 11→
 12→const PACKAGE_SEGMENT = "/packages/evals/";
 13→const EVAL_FRAMES = new Set(["[eval]", "[eval]-wrapper"]);
 14→const INTERNAL_FRAME_NAMES = new Set([
 15→  "readCallsites",
 16→  "readCallsitePath",
 17→  "resolveCallerFilePath",
 18→  "getCurrentFilePath",
 19→  "getCurrentDirPath",
 20→  "getRepoRootDir",
 21→  "getPackageRootDir",
 22→  "createRequireFromCaller",
 23→  "isMainModule",
 24→]);
 25→
 26→const normalizePath = (value: string): string => {
 27→  const input = value.startsWith("file://") ? fileURLToPath(value) : value;
 28→  return path.resolve(input).replaceAll("\\", "/");
 29→};
 30→
 31→const readCallsites = (): NodeJS.CallSite[] => {
 32→  const previousPrepare = Error.prepareStackTrace;
 33→  try {
 34→    Error.prepareStackTrace = (_, stack) => stack;
 35→    return (
 36→      (new Error().stack as unknown as NodeJS.CallSite[] | undefined) ?? []
 37→    );
 38→  } finally {
 39→    Error.prepareStackTrace = previousPrepare;
 40→  }
 41→};
 42→
 43→type CallSiteWithScriptName = NodeJS.CallSite & {
 44→  getScriptNameOrSourceURL?: () => string | null;
 45→};
 46→
 47→const readCallsitePath = (callsite: NodeJS.CallSite): string | null => {
 48→  const callsiteWithScript = callsite as CallSiteWithScriptName;
 49→  const rawPath =
 50→    callsite.getFileName() ?? callsiteWithScript.getScriptNameOrSourceURL?.();
 51→  if (!rawPath) return null;
 52→  if (rawPath.startsWith("node:")) return null;
 53→  if (EVAL_FRAMES.has(rawPath)) return null;
 54→  return normalizePath(rawPath);
 55→};
 56→
 57→const isInternalCallsite = (callsite: NodeJS.CallSite): boolean => {
 58→  const functionName = callsite.getFunctionName();
 59→  if (functionName && INTERNAL_FRAME_NAMES.has(functionName)) return true;
 60→
 61→  const methodName = callsite.getMethodName();
 62→  if (methodName && INTERNAL_FRAME_NAMES.has(methodName)) return true;
 63→
 64→  const callsiteString = callsite.toString();
 65→  for (const frameName of INTERNAL_FRAME_NAMES) {
 66→    if (callsiteString.includes(`${frameName} (`)) return true;
 67→    if (callsiteString.includes(`.${frameName} (`)) return true;
 68→  }
 69→  return false;
 70→};
 71→
 72→const resolveCallerFilePath = (): string => {
 73→  const packageCandidates: string[] = [];
 74→  const fallbackCandidates: string[] = [];
 75→
 76→  for (const callsite of readCallsites()) {
 77→    const filePath = readCallsitePath(callsite);
 78→    if (!filePath) continue;
 79→    if (isInternalCallsite(callsite)) continue;
 80→    if (filePath.includes(PACKAGE_SEGMENT)) {
 81→      packageCandidates.push(filePath);
 82→      continue;
 83→    }
 84→    fallbackCandidates.push(filePath);
 85→  }
 86→
 87→  const packageCandidate = packageCandidates[0];
 88→  if (packageCandidate) return packageCandidate;
 89→
 90→  const fallbackCandidate = fallbackCandidates[0];
 91→  if (fallbackCandidate) return fallbackCandidate;
 92→
 93→  throw new Error("Unable to resolve caller file path.");
 94→};
 95→
 96→export const getCurrentFilePath = (): string => resolveCallerFilePath();
 97→
 98→export const getCurrentDirPath = (): string =>
 99→  path.dirname(getCurrentFilePath());
100→
101→export const getRepoRootDir = (): string => {
102→  const currentFilePath = getCurrentFilePath();
103→  const index = currentFilePath.lastIndexOf(PACKAGE_SEGMENT);
104→  if (index === -1) {
105→    throw new Error(
106→      `Unable to determine repo root from ${currentFilePath} (missing ${PACKAGE_SEGMENT}).`,
107→    );
108→  }
109→  return currentFilePath.slice(0, index);
110→};
111→
112→export const getPackageRootDir = (): string =>
113→  `${getRepoRootDir()}${PACKAGE_SEGMENT.slice(0, -1)}`;
114→
115→export const createRequireFromCaller = () =>
116→  createRequire(getCurrentFilePath());
117→
118→export const isMainModule = (): boolean => {
119→  const entryScript = process.argv.at(1);
120→  if (!entryScript) return false;
121→  return normalizePath(entryScript) === getCurrentFilePath();
122→};
