  1→/**
  2→ * Initializes a V3 instance for use in evaluations without modifying
  3→ * the existing Stagehand-based init flow. Tasks can gradually migrate
  4→ * to consume `v3` directly.
  5→ */
  6→
  7→import type {
  8→  AvailableCuaModel,
  9→  AvailableModel,
 10→  AgentInstance,
 11→  ClientOptions,
 12→  LLMClient,
 13→  LocalBrowserLaunchOptions,
 14→  ModelConfiguration,
 15→  V3Options,
 16→  AgentModelConfig,
 17→} from "@browserbasehq/stagehand";
 18→import {
 19→  loadApiKeyFromEnv,
 20→  modelToAgentProviderMap,
 21→  V3,
 22→} from "@browserbasehq/stagehand";
 23→import { env } from "./env.js";
 24→import { EvalLogger } from "./logger.js";
 25→
 26→type InitV3Args = {
 27→  llmClient?: LLMClient;
 28→  modelClientOptions?: ClientOptions;
 29→  domSettleTimeoutMs?: number; // retained for parity; v3 handlers accept timeouts per-call
 30→  logger: EvalLogger;
 31→  createAgent?: boolean; // only create an agent for agent tasks
 32→  isCUA?: boolean;
 33→  configOverrides?: {
 34→    localBrowserLaunchOptions?: Partial<
 35→      Pick<LocalBrowserLaunchOptions, "headless" | "args">
 36→    >;
 37→    // Back-compat alias for args
 38→    chromeFlags?: string[];
 39→    browserbaseSessionCreateParams?: V3Options["browserbaseSessionCreateParams"];
 40→    browserbaseSessionID?: V3Options["browserbaseSessionID"];
 41→    experimental?: boolean;
 42→  };
 43→  actTimeoutMs?: number; // retained for parity (v3 agent tools don't use this globally)
 44→  modelName: AvailableModel;
 45→};
 46→
 47→export type V3InitResult = {
 48→  v3: V3;
 49→  logger: EvalLogger;
 50→  debugUrl?: string; // not exposed by v3; placeholder for parity
 51→  sessionUrl?: string; // not exposed by v3; placeholder for parity
 52→  modelName: AvailableModel;
 53→  agent?: AgentInstance;
 54→};
 55→
 56→export async function initV3({
 57→  llmClient,
 58→  modelClientOptions,
 59→  logger,
 60→  configOverrides,
 61→  modelName,
 62→  createAgent,
 63→  isCUA,
 64→}: InitV3Args): Promise<V3InitResult> {
 65→  // If CUA, choose a safe internal AISDK model for V3 handlers based on available API keys
 66→  let internalModel: AvailableModel = modelName;
 67→  if (isCUA) {
 68→    if (process.env.OPENAI_API_KEY)
 69→      internalModel = "openai/gpt-4.1-mini" as AvailableModel;
 70→    else if (
 71→      process.env.GEMINI_API_KEY ||
 72→      process.env.GOOGLE_GENERATIVE_AI_API_KEY
 73→    )
 74→      internalModel = "google/gemini-2.0-flash" as AvailableModel;
 75→    else if (process.env.ANTHROPIC_API_KEY)
 76→      internalModel = "anthropic/claude-3-7-sonnet-latest" as AvailableModel;
 77→    else
 78→      throw new Error(
 79→        "V3 init: No AISDK API key found. Set one of OPENAI_API_KEY, GEMINI_API_KEY/GOOGLE_GENERATIVE_AI_API_KEY, or ANTHROPIC_API_KEY to run CUA evals.",
 80→      );
 81→  }
 82→
 83→  const resolvedModelConfig: ModelConfiguration =
 84→    !isCUA && modelClientOptions
 85→      ? ({
 86→          ...modelClientOptions,
 87→          modelName: internalModel,
 88→        } as ModelConfiguration)
 89→      : internalModel;
 90→
 91→  const v3Options: V3Options = {
 92→    env,
 93→    apiKey: process.env.BROWSERBASE_API_KEY,
 94→    projectId: process.env.BROWSERBASE_PROJECT_ID,
 95→    localBrowserLaunchOptions: {
 96→      headless: configOverrides?.localBrowserLaunchOptions?.headless ?? false,
 97→      args:
 98→        configOverrides?.localBrowserLaunchOptions?.args ??
 99→        configOverrides?.chromeFlags,
100→    },
101→    model: resolvedModelConfig,
102→    experimental:
103→      typeof configOverrides?.experimental === "boolean"
104→        ? configOverrides.experimental && process.env.USE_API !== "true" // experimental only when not using API
105→        : false,
106→    verbose: 2,
107→    browserbaseSessionCreateParams:
108→      configOverrides?.browserbaseSessionCreateParams,
109→    browserbaseSessionID: configOverrides?.browserbaseSessionID,
110→    selfHeal: true,
111→    disablePino: true,
112→    disableAPI: process.env.USE_API !== "true", // Negate: USE_API=true → disableAPI=false
113→    serverCache: false,
114→    logger: logger.log.bind(logger),
115→  };
116→
117→  if (!isCUA && llmClient) {
118→    v3Options.llmClient = llmClient;
119→  }
120→
121→  const v3 = new V3(v3Options);
122→
123→  // Associate the logger with the V3 instance
124→  logger.init(v3);
125→  await v3.init();
126→
127→  let agent: AgentInstance | undefined;
128→  if (createAgent) {
129→    if (isCUA) {
130→      const shortModelName = modelName.includes("/")
131→        ? modelName.split("/")[1]
132→        : modelName;
133→
134→      const providerType = modelToAgentProviderMap[shortModelName];
135→      if (!providerType) {
136→        throw new Error(
137→          `CUA model "${shortModelName}" not found in modelToAgentProviderMap. ` +
138→            `Available: ${Object.keys(modelToAgentProviderMap).join(", ")}`,
139→        );
140→      }
141→
142→      const apiKey = loadApiKeyFromEnv(providerType, logger.log.bind(logger));
143→
144→      const cuaModel: AvailableCuaModel | AgentModelConfig<AvailableCuaModel> =
145→        apiKey && apiKey.length > 0
146→          ? {
147→              modelName: modelName as AvailableCuaModel,
148→              apiKey,
149→            }
150→          : (modelName as AvailableCuaModel);
151→
152→      agent = v3.agent({
153→        cua: true,
154→        model: cuaModel,
155→        systemPrompt: `You are a helpful assistant that must solve the task by browsing. At the end, produce a single line: "Final Answer: <answer>" summarizing the requested result (e.g., score, list, or text). ALWAYS OPERATE WITHIN THE PAGE OPENED BY THE USER, YOU WILL ALWAYS BE PROVIDED WITH AN OPENED PAGE, WHICHEVER TASK YOU ARE ATTEMPTING TO COMPLETE CAN BE ACCOMPLISHED WITHIN THE PAGE. Simple perform the task provided, do not overthink or overdo it. The user trusts you to complete the task without any additional instructions, or answering any questions.`,
156→      });
157→    } else {
158→      agent = v3.agent({
159→        model: modelName,
160→        executionModel: "google/gemini-2.5-flash",
161→      });
162→    }
163→  }
164→
165→  return {
166→    v3,
167→    logger,
168→    debugUrl: "",
169→    sessionUrl: "",
170→    modelName,
171→    agent,
172→  };
173→}
