108→function handleConfig(args: string[]): void {
109→  const config = loadConfig();
110→
111→  if (args.length === 0) {
112→    // Show current config
113→    console.log(chalk.blue.bold("\nCurrent Configuration"));
114→    console.log(chalk.cyan("\nDefaults:"));
115→    Object.entries(config.defaults).forEach(([key, value]) => {
116→      console.log(`  ${key}: ${chalk.yellow(value ?? "not set")}`);
117→    });
118→    return;
119→  }
120→
121→  if (args[0] === "set" && args.length >= 3) {
122→    const [, key, ...valueParts] = args;
123→    const value = valueParts.join(" ");
124→
125→    if (!(key in config.defaults)) {
126→      console.error(chalk.red(`Error: Unknown config key "${key}"`));
127→      console.log(
128→        chalk.dim(`Valid keys: ${Object.keys(config.defaults).join(", ")}`),
129→      );
130→      process.exit(1);
131→    }
132→
133→    // Parse value based on type
134→    let parsedValue: string | number | boolean | null = value;
135→    if (key === "trials" || key === "concurrency") {
136→      parsedValue = parseInt(value, 10);
137→      if (isNaN(parsedValue)) {
138→        console.error(chalk.red(`Error: ${key} must be a number`));
139→        process.exit(1);
140→      }
141→    } else if (key === "api") {
142→      parsedValue = value === "true";
143→    } else if (value === "null" || value === "none") {
144→      parsedValue = null;
145→    }
146→
147→    // Type-safe assignment
148→    if (key === "env") {
149→      config.defaults.env = parsedValue as string;
150→    } else if (key === "trials") {
151→      config.defaults.trials = parsedValue as number;
152→    } else if (key === "concurrency") {
153→      config.defaults.concurrency = parsedValue as number;
154→    } else if (key === "provider") {
155→      config.defaults.provider = parsedValue as string | null;
156→    } else if (key === "model") {
157→      config.defaults.model = parsedValue as string | null;
158→    } else if (key === "api") {
159→      config.defaults.api = parsedValue as boolean;
160→    }
161→    saveConfig(config);
162→    console.log(chalk.green(`✓ Set ${key} to ${parsedValue}`));
163→  } else if (args[0] === "reset") {
164→    const defaultConfig: Config["defaults"] = {
165→      env: "local",
166→      trials: 3,
167→      concurrency: 3,
168→      provider: null,
169→      model: null,
170→      api: false,
171→    };
172→
173→    if (args[1] && args[1] in config.defaults) {
174→      const key = args[1];
175→      // Type-safe reset by key
176→      if (key === "env") {
177→        config.defaults.env = defaultConfig.env;
178→      } else if (key === "trials") {
179→        config.defaults.trials = defaultConfig.trials;
180→      } else if (key === "concurrency") {
181→        config.defaults.concurrency = defaultConfig.concurrency;
182→      } else if (key === "provider") {
183→        config.defaults.provider = defaultConfig.provider;
184→      } else if (key === "model") {
185→        config.defaults.model = defaultConfig.model;
186→      } else if (key === "api") {
187→        config.defaults.api = defaultConfig.api;
188→      }
189→      saveConfig(config);
190→      console.log(chalk.green(`✓ Reset ${args[1]} to default`));
191→    } else if (!args[1]) {
192→      config.defaults = defaultConfig;
193→      saveConfig(config);
194→      console.log(chalk.green("✓ Reset all settings to defaults"));
195→    } else {
196→      console.error(chalk.red(`Error: Unknown config key "${args[1]}"`));
197→      process.exit(1);
198→    }
199→  } else if (args[0] === "path") {
200→    console.log(CONFIG_PATH);
201→  } else {
202→    console.error(chalk.red("Error: Invalid config command"));
203→    console.log(
204→      chalk.dim("Usage: evals config [set <key> <value> | reset [key] | path]"),
205→    );
206→    process.exit(1);
207→  }
208→}
