324→function handleRun(args: string[]): void {
325→  const config = loadConfig();
326→  const { options, target, filters } = parseArgs(args);
327→
328→  // Merge with defaults
329→  const stagehandTarget = (process.env.STAGEHAND_BROWSER_TARGET ?? "")
330→    .toLowerCase()
331→    .trim();
332→  if (
333→    !options.env &&
334→    (stagehandTarget === "local" || stagehandTarget === "browserbase")
335→  ) {
336→    options.env = stagehandTarget;
337→  }
338→  const finalOptions = { ...config.defaults, ...options };
339→
340→  // Build environment variables
341→  const env = { ...process.env };
342→
343→  // Set core environment variables
344→  if (finalOptions.env === "browserbase") {
345→    env.EVAL_ENV = "BROWSERBASE";
346→  } else {
347→    env.EVAL_ENV = "LOCAL";
348→  }
349→
350→  if (finalOptions.api) {
351→    env.USE_API = "true";
352→  }
353→
354→  if (finalOptions.trials) {
355→    env.EVAL_TRIAL_COUNT = String(finalOptions.trials);
356→  }
357→
358→  if (finalOptions.concurrency) {
359→    env.EVAL_MAX_CONCURRENCY = String(finalOptions.concurrency);
360→  }
361→
362→  if (finalOptions.provider) {
363→    env.EVAL_PROVIDER = finalOptions.provider;
364→  }
365→
366→  if (finalOptions.model) {
367→    env.EVAL_MODEL_OVERRIDE = finalOptions.model;
368→  }
369→
370→  // Handle benchmark-specific options
371→  let evalName: string | undefined;
372→  let categoryFilter: string | undefined;
373→
374→  if (target) {
375→    if (target.startsWith("b:") || target.startsWith("benchmark:")) {
376→      // Running a benchmark
377→      const benchmarkName = target.replace(/^(b:|benchmark:)/, "");
378→
379→      if (!config.benchmarks[benchmarkName]) {
380→        console.error(chalk.red(`Error: Unknown benchmark "${benchmarkName}"`));
381→        console.log(
382→          chalk.dim(
383→            `Available benchmarks: ${Object.keys(config.benchmarks).join(", ")}`,
384→          ),
385→        );
386→        process.exit(1);
387→      }
388→
389→      // Map to the actual eval name
390→      const benchmarkMap: Record<string, string> = {
391→        webbench: "agent/webbench",
392→        gaia: "agent/gaia",
393→        webvoyager: "agent/webvoyager",
394→        osworld: "agent/osworld",
395→        onlineMind2Web: "agent/onlineMind2Web",
396→        webtailbench: "agent/webtailbench",
397→      };
398→
399→      evalName = benchmarkMap[benchmarkName];
400→      env.EVAL_DATASET = benchmarkName;
401→
402→      // Set benchmark-specific options
403→      if (options.limit) {
404→        env.EVAL_MAX_K = String(options.limit);
405→        env[`EVAL_${benchmarkName.toUpperCase()}_LIMIT`] = String(
406→          options.limit,
407→        );
408→      }
409→
410→      if (options.sample) {
411→        env[`EVAL_${benchmarkName.toUpperCase()}_SAMPLE`] = String(
412→          options.sample,
413→        );
414→      }
415→
416→      // Apply filters
417→      filters.forEach(([key, value]) => {
418→        const envKey = `EVAL_${benchmarkName.toUpperCase()}_${key.toUpperCase()}`;
419→        env[envKey] = value;
420→      });
421→    } else if (target === "all") {
422→      // Run all evals (no filter)
423→    } else if (target.includes("/") || target.includes("*")) {
424→      // Pattern matching - treat as eval name
425→      evalName = target;
426→    } else {
427→      // Check if it's a category
428→      const categories = new Set<string>();
429→      config.tasks.forEach((task) => {
430→        task.categories.forEach((cat) => categories.add(cat));
431→      });
432→
433→      if (categories.has(target)) {
434→        categoryFilter = target;
435→      } else {
436→        // Assume it's a specific eval name
437→        evalName = target;
438→      }
439→    }
440→  }
441→
442→  // Build the legacy command
443→  const legacyArgs: string[] = [];
444→
445→  if (evalName) {
446→    legacyArgs.push(`name=${evalName}`);
447→  } else if (categoryFilter) {
448→    legacyArgs.push("category", categoryFilter);
449→  }
450→
451→  // Run the existing eval system with our environment
452→  console.log(chalk.blue.bold("\nRunning evals...\n"));
453→
454→  // Build first if needed
455→  const buildChild = spawn("pnpm", ["run", "build"], {
456→    stdio: "inherit",
457→    shell: true,
458→  });
459→
460→  buildChild.on("exit", (buildCode) => {
461→    if (buildCode !== 0) {
462→      process.exit(buildCode || 1);
463→    }
464→
465→    const compiledEvalPath = path.resolve(
466→      moduleDir,
467→      "..",
468→      "esm",
469→      "index.eval.js",
470→    );
471→    // When built to packages/evals/dist/cli/cli.js, moduleDir is packages/evals/dist/cli/
472→    // Source is at packages/evals/index.eval.ts from repo root
473→    const sourceEvalPath = path.resolve(
474→      moduleDir,
475→      "..",
476→      "..",
477→      "packages",
478→      "evals",
479→      "index.eval.ts",
480→    );
481→
482→    let child;
483→
484→    if (fs.existsSync(compiledEvalPath)) {
485→      child = spawn(process.execPath, [compiledEvalPath, ...legacyArgs], {
486→        env,
487→        stdio: "inherit",
488→        shell: true,
489→      });
490→    } else {
491→      let tsxCliPath: string | undefined;
492→      try {
493→        // Resolve the local tsx CLI entry within this package installation
494→        // This avoids requiring a globally installed tsx binary
495→        tsxCliPath = require.resolve("tsx/dist/cli.js");
496→      } catch {
497→        // no-op; will fall back to shell-resolved "tsx" if not found
498→      }
499→
500→      const tsxArgs = [sourceEvalPath, ...legacyArgs];
501→
502→      if (tsxCliPath) {
503→        child = spawn(process.execPath, [tsxCliPath, ...tsxArgs], {
504→          env,
505→          stdio: "inherit",
506→          shell: true,
507→        });
508→      } else {
509→        child = spawn("tsx", tsxArgs, {
510→          env,
511→          stdio: "inherit",
512→          shell: true,
513→        });
514→      }
515→    }
516→
517→    child.on("exit", (code) => {
518→      process.exit(code || 0);
519→    });
520→
521→    // Forward SIGINT (Ctrl+C) and SIGTERM to child process
522→    process.on("SIGINT", () => {
523→      console.log("\n\nReceived SIGINT, killing child process...");
524→      child.kill("SIGINT");
525→      setTimeout(() => {
526→        child.kill("SIGKILL");
527→        process.exit(130);
528→      }, 1000);
529→    });
530→
531→    process.on("SIGTERM", () => {
532→      console.log("\n\nReceived SIGTERM, killing child process...");
533→      child.kill("SIGTERM");
534→      setTimeout(() => {
535→        child.kill("SIGKILL");
536→        process.exit(143);
537→      }, 1000);
538→    });
539→  });
540→}
541→
542→// Main CLI logic
543→function main(): void {
544→  const args = process.argv.slice(2);
545→  const command = args[0];
546→  const commandArgs = args.slice(1);
547→
548→  switch (command) {
549→    case "run":
550→      handleRun(commandArgs);
551→      break;
552→
553→    case "list":
554→      handleList(commandArgs);
555→      break;
556→
557→    case "config":
558→      handleConfig(commandArgs);
559→      break;
560→
561→    case "help":
562→    case "--help":
563→    case "-h":
564→      printHelp();
565→      break;
566→
567→    case undefined:
568→      console.error(chalk.red("Error: No command specified"));
569→      printHelp();
570→      process.exit(1);
571→      break;
572→
573→    default:
574→      // Check if it's a direct target (backward compatibility)
575→      if (!command.startsWith("-")) {
576→        handleRun(args);
577→      } else {
578→        console.error(chalk.red(`Error: Unknown command "${command}"`));
579→        printHelp();
580→        process.exit(1);
581→      }
582→  }
583→}
584→
585→// Run the CLI
586→main();
